INTRO: PROC OPTIONS(MAIN);
  DCL WS-MSG CHAR(30) INIT('WELCOME TO CICS');

  EXEC CICS SEND TEXT FROM(WS-MSG) LENGTH(LENGTH(WS-MSG));
END INTRO;

CORE: PROC OPTIONS(MAIN);
  DCL 1 WS-COMMAREA,
        2 WS-TEXT CHAR(20);

  WS-TEXT = 'HELLO FROM CICS';

  EXEC CICS LINK PROGRAM('PGM002') COMMAREA(WS-COMMAREA) LENGTH(LENGTH(WS-COMMAREA));
END CORE;

ADVANCED: PROC OPTIONS(MAIN);
  DCL WS-RESP FIXED BIN(31);
  DCL WS-RESP2 FIXED BIN(31);
  DCL WS-MSG CHAR(30);
  DCL CUSTOMER-REC CHAR(100);
  DCL CUSTOMER-KEY CHAR(10) INIT('CUST000001');

  EXEC CICS READ FILE('CUSTFILE')
       INTO(CUSTOMER-REC)
       RIDFLD(CUSTOMER-KEY)
       RESP(WS-RESP)
       RESP2(WS-RESP2);

  IF WS-RESP = DFHRESP(NORMAL) THEN
    WS-MSG = 'RECORD FOUND';
  ELSE
    WS-MSG = 'RECORD NOT FOUND';

  EXEC CICS SEND TEXT FROM(WS-MSG) LENGTH(LENGTH(WS-MSG));
END ADVANCED;
